CREATE PROCEDURE dbo.usp_place_order
    @customer_id INT,
    @product_id INT,
    @quantity INT
AS
BEGIN
    SET NOCOUNT ON;
    DECLARE @price DECIMAL(10,2);
    DECLARE @stock INT;
    DECLARE @order_id INT;

-- Assign user to role
ALTER ROLE app_readonly ADD MEMBER [analyst@company.com];

-- Application service principal with write access
CREATE USER [app-service-principal] FROM EXTERNAL PROVIDER;
GRANT SELECT, INSERT, UPDATE, DELETE ON SCHEMA::dbo
    TO [app-service-principal];
GRANT EXECUTE ON SCHEMA::dbo TO [app-service-principal];

// Available render types: timechart, barchart, columnchart,
//   piechart, scatterchart, areachart, stackedareachart,
//   ladderchart, pivotchart, anomalychart

// Pattern 1: Add a filter
Revenue North =
CALCULATE(
    [Total Revenue],
    dim_customer[region] = "North"
)
// Evaluates Total Revenue but forces Region = North,
// regardless of any region slicer on the report

// Pattern 2: Remove a filter (percentage of total)
Revenue % of Total =
DIVIDE(
    [Total Revenue],
    CALCULATE([Total Revenue], ALL(dim_customer[region]))
)
// ALL() removes the region filter, giving the grand total
// as the denominator

// Pattern 3: Remove all filters on a table
Revenue % of Grand Total =
DIVIDE(
    [Total Revenue],
    CALCULATE([Total Revenue], ALL(fact_orders))
)

// Pattern 4: Keep only specific filters
Revenue Same Product All Regions =
CALCULATE(
    [Total Revenue],
    ALLEXCEPT(fact_orders, dim_product[category])
)
// Removes all filters EXCEPT product category

// Rolling 12-month total
Rolling 12M Revenue =
CALCULATE(
    [Total Revenue],
    DATESINPERIOD(dim_date[Date], MAX(dim_date[Date]), -12, MONTH)
)

// Previous month
Revenue Previous Month =
CALCULATE(
    [Total Revenue],
    DATEADD(dim_date[Date], -1, MONTH)
)

// Weighted average price
Weighted Avg Price =
DIVIDE(
    SUMX(fact_order_items, fact_order_items[quantity] * fact_order_items[unit_price]),
    SUM(fact_order_items[quantity])
)

// Revenue from Top 10 customers only
Top 10 Customer Revenue =
CALCULATE(
    [Total Revenue],
    TOPN(10, ALL(dim_customer), [Total Revenue], DESC)
)

// Dynamic measure selected by user via slicer
// (create a disconnected table: Metric = {"Revenue", "Orders", "Avg Order"})
Selected Metric =
SWITCH(
    SELECTEDVALUE(MetricSelector[Metric]),
    "Revenue", [Total Revenue],
    "Orders", [Total Orders],
    "Avg Order", [Average Order Value],
    BLANK()
)

